var triangularSum = function(nums) {
    let cur = nums.slice();
    while (cur.length > 1) {
        const next = [];
        for (let i = 0; i < cur.length - 1; i++) {
            next.push((cur[i] + cur[i + 1]) % 10);
        }
        cur = next;
    }
    return cur[0];
};
